import{_ as i,o as l,c as a,a3 as t}from"./chunks/framework.DACwFHq9.js";const u=JSON.parse('{"title":"正则管道 (Regex Pipeline)","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/context-pipeline/regex-pipeline.md","filePath":"user-guide/tools/llm-chat/context-pipeline/regex-pipeline.md","lastUpdated":1778239080000}'),r={name:"user-guide/tools/llm-chat/context-pipeline/regex-pipeline.md"};function n(o,e,s,d,p,g){return l(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="正则管道-regex-pipeline" tabindex="-1">正则管道 (Regex Pipeline) <a class="header-anchor" href="#正则管道-regex-pipeline" aria-label="Permalink to &quot;正则管道 (Regex Pipeline)&quot;">​</a></h1><p>正则管道是 LLM Chat 中功能最强大的文本处理系统，它允许你通过正则表达式和自定义脚本对消息内容进行全自动的清洗、转换和增强。</p><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><p>正则管道基于“匹配-替换”逻辑，但针对聊天场景进行了深度定制：</p><ul><li><strong>多层级合并</strong>：规则可以定义在全局、智能体或用户层级，系统会自动合并应用。</li><li><strong>双阶段应用</strong>：区分“渲染层”（仅影响你看到的 UI）和“请求层”（影响发送给 AI 的上下文）。</li><li><strong>脚本引擎</strong>：除了简单的文本替换，还支持使用 JavaScript 编写复杂的处理逻辑。</li></ul><hr><h2 id="三层配置体系" tabindex="-1">三层配置体系 <a class="header-anchor" href="#三层配置体系" aria-label="Permalink to &quot;三层配置体系&quot;">​</a></h2><p>系统从三个来源收集正则规则，并按优先级合并：</p><ol><li><strong>全局配置 (Global)</strong>：在“设置 -&gt; 插件/正则”中定义，适用于所有会话。</li><li><strong>智能体配置 (Agent)</strong>：在智能体编辑器中定义，仅当该智能体参与对话时生效。</li><li><strong>用户配置 (User)</strong>：在用户个人资料中定义，仅当该用户发送消息时生效。</li></ol><h3 id="绑定模式-binding-mode" tabindex="-1">绑定模式 (Binding Mode) <a class="header-anchor" href="#绑定模式-binding-mode" aria-label="Permalink to &quot;绑定模式 (Binding Mode)&quot;">​</a></h3><p>在正则配置面板中，你可以选择规则的绑定策略：</p><ul><li><strong>跟随消息 (Message Mode)</strong>：默认模式。每条消息在生成时会“冻结”当前的正则配置。即使后续修改了智能体的正则规则，旧消息的渲染也不会改变。</li><li><strong>跟随会话 (Session Mode)</strong>：所有消息始终使用当前会话中智能体/用户的最新正则配置进行渲染。</li></ul><hr><h2 id="双管道集成" tabindex="-1">双管道集成 <a class="header-anchor" href="#双管道集成" aria-label="Permalink to &quot;双管道集成&quot;">​</a></h2><p>规则可以根据其用途，被指派到不同的处理阶段：</p><h3 id="_1-渲染管道-render-pipeline" tabindex="-1">1. 渲染管道 (Render Pipeline) <a class="header-anchor" href="#_1-渲染管道-render-pipeline" aria-label="Permalink to &quot;1. 渲染管道 (Render Pipeline)&quot;">​</a></h3><ul><li><strong>触发时机</strong>：消息显示在屏幕上之前。</li><li><strong>用途</strong>：UI 增强（如将 <code>&lt;think&gt;</code> 标签转为折叠框）、隐私脱敏（隐藏 API Key）、口癖转换、格式美化。</li><li><strong>特性</strong>：不改变数据库中的原始存储，也不影响发送给 AI 的内容。</li></ul><h3 id="_2-请求管道-request-pipeline" tabindex="-1">2. 请求管道 (Request Pipeline) <a class="header-anchor" href="#_2-请求管道-request-pipeline" aria-label="Permalink to &quot;2. 请求管道 (Request Pipeline)&quot;">​</a></h3><ul><li><strong>触发时机</strong>：消息发送给 LLM 接口之前。</li><li><strong>用途</strong>：上下文压缩（移除不必要的冗余信息）、提示词注入、特定格式强制转换。</li><li><strong>特性</strong>：直接影响 AI 接收到的文本，是实现高级 Agent 逻辑的关键。</li></ul><hr><h2 id="规则配置详解" tabindex="-1">规则配置详解 <a class="header-anchor" href="#规则配置详解" aria-label="Permalink to &quot;规则配置详解&quot;">​</a></h2><p>每条规则包含以下核心参数：</p><h3 id="基础配置" tabindex="-1">基础配置 <a class="header-anchor" href="#基础配置" aria-label="Permalink to &quot;基础配置&quot;">​</a></h3><ul><li><strong>正则表达式</strong>：标准的 JS 正则表达式。支持 <code>/pattern/flags</code> 格式。</li><li><strong>替换内容</strong>： <ul><li>**简单</li></ul></li></ul>',24)])])}const c=i(r,[["render",n]]);export{u as __pageData,c as default};
